  uint32_t h_in = x_shape->GetDim(2);
  uint32_t w_in = x_shape->GetDim(3);

  uint32_t c_out = w_shape->GetDim(0);
  uint32_t k_h = w_shape->GetDim(2);
  uint32_t k_w = w_shape->GetDim(3);

  const gert::RuntimeAttrs *attrs = context->GetAttrs();
  const int64_t *stride_attr = attrs->GetAttrPointer<int64_t>(0);
  const int64_t *padding_attr = attrs->GetAttrPointer<int64_t>(1);
  const int64_t *out_pad_attr = attrs->GetAttrPointer<int64_t>(2);

  uint32_t stride_h = static_cast<uint32_t>(stride_attr[0]);
  uint32_t stride_w = static_cast<uint32_t>(stride_attr[1]);
  uint32_t pad_h = static_cast<uint32_t>(padding_attr[0]);
  uint32_t pad_w = static_cast<uint32_t>(padding_attr[1]);
  uint32_t out_pad_h = static_cast<uint32_t>(out_pad_attr[0]);
  uint32_t out_pad_w = static_cast<uint32_t>(out_pad_attr[1]);

  uint32_t h_out = (h_in - 1) * stride_h + k_h - 2 * pad_h + out_pad_h;
  uint32_t w_out = (w_in - 1) * stride_w + k_w - 2 * pad_w + out_pad_w;

  uint32_t totalElements = n * c_out * h_out * w_out;
  uint32_t elemSize = sizeof(float);
  uint32_t maxTile = (UB_SIZE / elemSize) / 8;  // conservative for vec accum
  maxTile = (maxTile / ALIGN) * ALIGN;
  if (maxTile < ALIGN) maxTile = ALIGN;
  uint32_t tileLength = std::min(totalElements, maxTile);
  if (tileLength == 0) tileLength = ALIGN;
  tileLength = (tileLength / ALIGN) * ALIGN;
  if (tileLength > totalElements) tileLength = totalElements;

  uint32_t blockDim = 8;
  context->SetBlockDim(blockDim);

  tiling.n = n;
  tiling.c_in = c_in;
  tiling.h_in = h_in;
  tiling.w_in = w_in;
  tiling.c_out = c_out;
  tiling.k_h = k_h;
  tiling.k_w = k_w;
  tiling.stride_h = stride_h;
  tiling.stride_w = stride_w;
  tiling.pad_h = pad_h;
  tiling.pad_w = pad_w;
  tiling.out_pad_h = out_pad_h;
  tiling.out_pad_w = out_pad_w;
  tiling.h_out = h_out;
  tiling.w_out = w_out;
  tiling.totalElements = totalElements;
  tiling.tileLength = tileLength;
  tiling.hasBias = (context->GetInputShape(2) != nullptr) ? 1.0f : 0.0f;

